assistantMessages:
I'll check your MetaMask agent wallet balance right away!

```typescript
import { chromium } from 'playwright';
import * as path from 'path';
import * as os from 'os';

// Configuration
const PROFILE_PATH = path.join(os.homedir(), '.agent-wallet', 'chrome-profile');
const METAMASK_EXTENSION_ID = 'nkbihfbeogaeaoehlefnkodbefgpgknn';

async function getWalletBalance() {
  console.log('ü¶ä Launching MetaMask browser...');

  // Launch browser with MetaMask extension
  const browser = await chromium.launchPersistentContext(PROFILE_PATH, {
    headless: false,
    args: [
      `--disable-extensions-except=${PROFILE_PATH}/extensions/metamask`,
      `--load-extension=${PROFILE_PATH}/extensions/metamask`,
    ],
  });

  const page = await browser.newPage();

  try {
    // Navigate to MetaMask's internal page to read balances
    console.log('üìä Opening MetaMask...');
    await page.goto(`chrome-extension://${METAMASK_EXTENSION_ID}/home.html`);
    await page.waitForLoadState('networkidle');
    await page.waitForTimeout(2000);

    // Wait for MetaMask to fully load
    await page.waitForSelector('[data-testid="eth-overview__primary-currency"]', {
      timeout: 15000,
    });

    // Extract ETH balance
    const ethBalance = await page.$eval(
      '[data-testid="eth-overview__primary-currency"]',
      (el) => el.textContent?.trim() ?? '0'
    );

    // Extract USD value
    const usdValue = await page.$eval(
      '[data-testid="eth-overview__secondary-currency"]',
      (el) => el.textContent?.trim() ?? '$0.00'
    ).catch(() => 'N/A');

    // Get wallet address
    const walletAddress = await page.$eval(
      '[data-testid="address-copy-button-text"]',
      (el) => el.textContent?.trim() ?? 'Unknown'
    ).catch(() => 'Unknown');

    // Get network name
    const networkName = await page.$eval(
      '[data-testid="network-display"]',
      (el) => el.textContent?.trim() ?? 'Unknown'
    ).catch(() => 'Unknown');

    // Try to get token balances from the token list
    const tokenBalances: Array<{ symbol: string; balance: string; usd: string }> = [];

    // Click on "Tokens" tab if available
    const tokensTab = await page.$('[data-testid="home__asset-tab"]');
    if (tokensTab) {
      await tokensTab.click();
      await page.waitForTimeout(1000);

      // Extract token list items
      const tokens = await page.$$eval(
        '[data-testid="multichain-token-list-item"]',
        (items) => items.map((item) => {
          const symbol = item.querySelector('[data-testid="multichain-token-list-item-token-name"]')
            ?.textContent?.trim() ?? '';
          const balance = item.querySelector('[data-testid="multichain-token-list-item-secondary"]')
            ?.textContent?.trim() ?? '';
          const usd = item.querySelector('[data-testid="multichain-token-list-item-primary"]')
            ?.textContent?.trim() ?? '';
          return { symbol, balance, usd };
        })
      ).catch(() => []);

      tokenBalances.push(...tokens);
    }

    // Display results
    console.log('\n' + '‚ïê'.repeat(50));
    console.log('üíº AGENT WALLET BALANCE');
    console.log('‚ïê'.repeat(50));
    console.log(`üìç Address:  ${walletAddress}`);
    console.log(`üåê Network:  ${networkName}`);
    console.log('‚îÄ'.repeat(50));
    console.log(`‚üÝ  ETH:      ${ethBalance}`);
    console.log(`üíµ USD Value: ${usdValue}`);

    if (tokenBalances.length > 0) {
      console.log('‚îÄ'.repeat(50));
      console.log('ü™ô TOKEN BALANCES:');
      tokenBalances.forEach(({ symbol, balance, usd }) => {
        if (symbol && balance) {
          console.log(`   ${symbol.padEnd(10)} ${balance.padEnd(20)} ${usd}`);
        }
      });
    }

    console.log('‚ïê'.repeat(50));

    return {
      address: walletAddress,
      network: networkName,
      eth: ethBalance,
      usdValue,
      tokens: tokenBalances,
    };

  } catch (error) {
    console.error('‚ùå Error reading wallet balance:', error);

    // Provide helpful diagnostics
    console.log('\nüîç Diagnostic info:');
    console.log(`   Profile path: ${PROFILE_PATH}`);
    console.log('   Make sure MetaMask is installed and unlocked');
    console.log('   Run "npm run setup" if this is your first time');

    throw error;
  } finally {
    await browser.close();
  }
}

// Run the balance check
getWalletBalance()
  .then((balance) => {
    console.log('\n‚úÖ Balance check complete');
    process.exit(0);
  })
  .catch((err) => {
    console.error('\n‚ùå Failed to get balance:', err.message);
    process.exit(1);
  });
```

