assistantMessages:
I'll help you swap 0.1 ETH to USDC. Let me walk through this step by step.

## Step 1: Check Permissions & Balance

First, let me verify the swap is within configured limits and check the wallet balance.

```typescript
// src/guard.ts - Permission check
import { permissions } from './config';
import { getUSDPrice } from './price';

async function checkSwapPermission(amountETH: number): Promise<GuardResult> {
  // Get current ETH price
  const ethPrice = await getUSDPrice('ETH');
  const usdValue = amountETH * ethPrice;

  console.log(`Swap value: ${amountETH} ETH ‚âà $${usdValue.toFixed(2)}`);

  // Check per-tx limit
  const perTxLimit = parseInt(permissions.constraints.spendLimit.perTx) / 1e6;
  if (usdValue > perTxLimit) {
    return { 
      allowed: false, 
      reason: `Exceeds per-tx limit: $${usdValue.toFixed(2)} > $${perTxLimit}` 
    };
  }

  // Check daily limit
  const dailySpent = await getDailySpent();
  const dailyLimit = parseInt(permissions.constraints.spendLimit.daily) / 1e6;
  if (dailySpent + usdValue > dailyLimit) {
    return { 
      allowed: false, 
      reason: `Would exceed daily limit: $${(dailySpent + usdValue).toFixed(2)} > $${dailyLimit}` 
    };
  }

  // Check chain is allowed (Ethereum mainnet = 1)
  if (!permissions.constraints.allowedChains.includes(1)) {
    return { allowed: false, reason: 'Ethereum mainnet not in allowedChains' };
  }

  return { allowed: true, estimatedUSD: usdValue };
}
```

## Step 2: Launch Browser & Connect to Uniswap

```typescript
// src/browser.ts - Launch isolated browser session
import { chromium } from 'playwright';
import path from 'path';

async function launchAgentBrowser() {
  const profilePath = path.join(process.env.HOME!, '.agent-wallet/chrome-profile');

  const browser = await chromium.launchPersistentContext(profilePath, {
    headless: false,           // MetaMask requires headed mode
    args: [
      `--disable-extensions-except=${METAMASK_PATH}`,
      `--load-extension=${METAMASK_PATH}`,
      '--no-sandbox',
    ],
    viewport: { width: 1280, height: 720 },
  });

  console.log('‚úì Browser launched with MetaMask extension');
  return browser;
}

async function connectToUniswap(context: BrowserContext) {
  const page = await context.newPage();

  // Navigate to Uniswap
  await page.goto('https://app.uniswap.org/swap');
  await page.waitForLoadState('networkidle');
  console.log('‚úì Navigated to Uniswap');

  // Click "Connect Wallet"
  await page.click('[data-testid="navbar-connect-wallet"]');
  await page.waitForSelector('[data-testid="wallet-option-MetaMask"]');
  await page.click('[data-testid="wallet-option-MetaMask"]');

  // Handle MetaMask popup
  await handleMetaMaskConnect(context);
  console.log('‚úì Wallet connected to Uniswap');

  return page;
}
```

## Step 3: Configure the Swap

```typescript
// src/wallet.ts - Set up swap parameters
async function configureSwap(page: Page, amountETH: string) {
  // Ensure ETH is selected as input token
  const inputToken = await page.$('[data-testid="swap-currency-input"] [data-testid="token-symbol"]');
  const inputSymbol = await inputToken?.textContent();

  if (inputSymbol !== 'ETH') {
    await page.click('[data-testid="swap-currency-input"] [data-testid="open-currency-select-button"]');
    await page.fill('[data-testid="token-search-input"]', 'ETH');
    await page.click('[data-testid="token-item-ETH"]');
  }

  // Select USDC as output token
  await page.click('[data-testid="swap-currency-output"] [data-testid="open-currency-select-button"]');
  await page.fill('[data-testid="token-search-input"]', 'USDC');
  // Select mainnet USDC (not bridged versions)
  await page.click('[data-testid="token-item-0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48"]');

  // Enter amount
  await page.fill('[data-testid="swap-currency-input"] input', amountETH);
  await page.waitForTimeout(1500); // Wait for quote to load

  // Read the quoted output
  const outputAmount = await page.$eval(
    '[data-testid="swap-currency-output"] input',
    (el: HTMLInputElement) => el.value
  );

  console.log(`‚úì Swap configured: ${amountETH} ETH ‚Üí ~${outputAmount} USDC`);
  return outputAmount;
}
```

## Step 4: Review Quote & Execute

```typescript
// src/index.ts - Final execution with approval check
async function executeSwap() {
  // --- Permission Check ---
  const guard = await checkSwapPermission(0.1);
  if (!guard.allowed) {
    throw new Error(`Blocked by guard: ${guard.reason}`);
  }

  // Check if approval required (e.g., value > $25 threshold)
