```typescript
// guard.ts
import { ethers } from 'ethers';
import { getUSDPrice } from './price';
import { loadPermissions } from './config';

export interface GuardResult {
  allowed: boolean;
  requiresApproval: boolean;
  reason?: string;
}

export async function checkGuard(intent: TransactionIntent): Promise<GuardResult> {
  const perms = loadPermissions();

  // 1. Check chain
  if (!perms.constraints.allowedChains.includes(intent.chainId)) {
    return { allowed: false, requiresApproval: false, reason: `Chain ${intent.chainId} not allowed` };
  }

  // 2. Check protocol
  const toAddr = intent.to.toLowerCase();
  const allowed = perms.constraints.allowedProtocols
    .map(a => a.toLowerCase())
    .includes(toAddr);
  if (!allowed) {
    return { allowed: false, requiresApproval: false, reason: `Protocol ${intent.to} not in allowlist` };
  }

  // 3. Estimate USD value
  const usdValue = await estimateUSDValue(intent);
  console.log(`[guard] Estimated USD value: $${(usdValue / 1e6).toFixed(2)}`);

  // 4. Check per-tx limit
  if (usdValue > BigInt(perms.constraints.spendLimit.perTx)) {
    return { allowed: false, requiresApproval: false, reason: `Exceeds per-tx limit` };
  }

  // 5. Check daily limit
  const dailySpent = await getDailySpent();
  if (dailySpent + usdValue > BigInt(perms.constraints.spendLimit.daily)) {
    return { allowed: false, requiresApproval: false, reason: `Exceeds daily limit` };
  }

  // 6. Check approval threshold
  const approvalThreshold = BigInt(perms.constraints.requireApproval.above);
  if (usdValue > approvalThreshold) {
    return { allowed: true, requiresApproval: true };
  }

  return { allowed: true, requiresApproval: false };
}
```

